#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int colors[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &colors[i]);
    }
    int max_count = 0;
    for (int i = 0; i < n; i++) {
        int count = 0;
        for (int j = 0; j < n; j++) {
            if (colors[j] != colors[i]) {
                count++;
            }
        }
        if (count > max_count) {
            max_count = count;
        }
    }
    printf("%d\n", max_count);
    return 0;
}

