const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let colors;
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        colors = input.split(' ').map(Number);
        let max_count = 0;
        for (let i = 0; i < n; i++) {
            let count = 0;
            for (let j = 0; j < n; j++) {
                if (colors[j] !== colors[i]) {
                    count++;
                }
            }
            if (count > max_count) {
                max_count = count;
            }
        }
        console.log(max_count);
        rl.close();
    }
});
